async function testConfigsExist() {
  // Verify all required configs exist with correct values
  const forecastHours = config.get('DEFAULT_FORECAST_HOURS');
  assertEquals(forecastHours, 48, 'DEFAULT_FORECAST_HOURS should be 48');

  const sampleDistance = config.get('DIRECTION_SAMPLE_DISTANCE_NM');
  assertEquals(sampleDistance, 30, 'DIRECTION_SAMPLE_DISTANCE_NM should be 30');

  const compassDirs = config.get('COMPASS_DIRECTIONS');
  assertEquals(compassDirs, 8, 'COMPASS_DIRECTIONS should be 8');
}
